48	const PROCESSING_FEE = 5;
49	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
50	
51	const BASE_PREMIUMS: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	};
58	
59	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
60	
61	const RUNE_BLOCK_SIZE = 3;
62	const RUNE_BLOCK_DISCOUNT = 15;
63	
64	const runeBlockDiscount = (items: Item[]): number => {
65	  const runeCount = items.filter((i) => i.type === "rune").length;
66	  return runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_DISCOUNT : 0;
67	};
68	
69	const sumBasePremiums = (items: Item[]): number =>
70	  items.reduce((sum, item) => sum + basePremiumFor(item), 0) - runeBlockDiscount(items);
71	
72	const quotePremium = (items: Item[]): number => {
73	  const base = sumBasePremiums(items);
74	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
75	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
76	};
77	
78	const claimPayout = (_step: ClaimStep): StepResult => ({
79	  payout: 0,
80	  remainingCap: 0,
81	});
82	
83	const runStep = (step: Step): StepResult =>
84	  step.op === "quote"
85	    ? { premium: quotePremium(step.items) }
86	    : claimPayout(step);
87	
88	export const runScenario = (scenario: Scenario): ScenarioResult => ({
89	  results: scenario.steps.map(runStep),
90	});
